import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ServiceSetting } from '../../models/workspace.models';

@Component({
  selector: 'app-admin-settings',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './settings.component.html',
  styleUrl: './settings.component.css',
})
export class AdminSettingsComponent {
  // DATA CONTRACT: backend-provided. mockup_cleaner empties this;
  // service_agent wires it to GET /api/admin/settings in ngOnInit().
  settings = signal<ServiceSetting[]>([
    { key: 'postgresql', label: 'PostgreSQL', value: '••••••••••••', configured: true },
    { key: 'minio', label: 'MinIO Object Storage', value: '', configured: false },
  ]);

  // Draft values for the credential forms (client-only until saved).
  drafts: Record<string, string> = {};
  savedKey = signal<string | null>(null);

  save(setting: ServiceSetting): void {
    const value = (this.drafts[setting.key] ?? '').trim();
    if (!value) return;
    this.settings.update((list) =>
      list.map((s) => (s.key === setting.key ? { ...s, value: '••••••••••••', configured: true } : s)),
    );
    this.drafts[setting.key] = '';
    this.savedKey.set(setting.key);
  }
}
